VALUES
  ('pukao-7c4986e7-moex-00017', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司本年度的銷貨收入與去年相當，但期末應收帳款與存貨均大幅增加。根據財務報表分析基 本原則，下列那一項最合理地解釋這一情況？', '["公司收現能力提升，且銷貨暢旺造成庫存不足", "公司收現速度變慢，且存貨周轉速度下降", "公司提高銷貨價格，導致帳款與庫存增加", "公司應收帳款與存貨同時增加，代表利潤穩定且現金流改善"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00018', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司X1年度淨利為$25,000，另提供下列資訊： 折舊費用：$5,000 應收帳款增加：$3,000 存貨減少：$2,000 購置設備支出：$6,000 發行普通股收現：$10,000 發放現金股利：$4,000 請問，下列那一組金額正確反映甲公司 X1 年度的營業活動、投資活動、籌資活動之現金流量， 以及現金及約當現金淨增減數？其中以括號()表示現金流出。', '["營業活動：$29,000；投資活動：($6,000)；籌資活動：$6,000；現金及約當現金淨增加數：$29,000", "營業活動：$29,000；投資活動：($6,000)；籌資活動：$6,000；現金及約當現金淨增加數：$25,000", "營業活動：$27,000；投資活動：($6,000)；籌資活動：$10,000；現金及約當現金淨增加數：$31,000", "營業活動：$29,000；投資活動：($6,000)；籌資活動：$10,000；現金及約當現金淨增加數：$33,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00019', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司截至X1年12月31日的資產為$100,000，負債為$30,000。該公司已發行累積特別股2,000 股（面額每股$10，年股利率10%），並於X1年底累積未支付X0年與X1年兩年度之股利。另有 普通股5,000股（面額每股$10）全年流通在外。X1年度未宣告任何股利，X1年淨利為$8,000。 請問：X1年底普通股每股淨值為何？', '["$9.20", "$13.20", "$14.00", "$15.00 41430"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00020', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '承上題，請問：X1年底每股盈餘？', '["$1.00", "$1.20", "$1.4", "$1.6"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00021', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年1月1日發行面額$100,000、票面利率6%、5年期公司債，發行價格為$92,000。 每年1月1日付息，共五期。公司採用有效利息法攤銷折價，市場有效利率為8%。請問：截至 X1年12月31日止，下列有關該公司債之財務報導金額何者正確？', '["損益表利息費用為$6,000；資產負債表應付公司債帳面金額為$92,000", "損益表利息費用為$7,360；資產負債表應付公司債帳面金額為$92,000", "損益表利息費用為$7,360；資產負債表應付公司債帳面金額為$93,360", "損益表利息費用為$6,000；資產負債表應付公司債帳面金額為$93,360"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00022', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '下列何者不屬於「負債準備」之適當範疇？', '["公司長期提供產品保固服務，雖無法律強制規定，但因一貫對外承諾與實務慣例，構成推定義務", "公司已正式對外公告重組計畫，並於報導日前通知受影響員工，預計產生解僱費用", "公司預計在未來年度進行廠房設備升級，以因應新的產品線，尚未簽約或對外承諾", "公司過去於顧客退貨時多會接受退貨，雖契約無退貨條款，市場亦普遍預期可退"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00023', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '某公司採用定期盤存制與加權平均法，期初有商品3單位單價為$500，本期又進貨7單位單價為 $700，期末剩下2單位。請問期末存貨價值為？', '["$1,000", "$1,280", "$1,300", "$1,400"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00024', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年4月1日以$10,000購入一項設備，估計使用年限為5年，殘值為$1,000。計算X1 年底止的第一年折舊費用，分別採用以下三種折舊方法：⑴直線法，⑵年數合計法，以及⑶倍數 （雙倍）餘額遞減法', '["直線法$1,350；年數合計法$1,800；倍數（雙倍）餘額遞減法$3,000", "直線法$1,350；年數合計法$2,250；倍數（雙倍）餘額遞減法$3,000", "直線法$1,800；年數合計法$2,400；倍數（雙倍）餘額遞減法$3,200", "直線法$1,350；年數合計法$2,160；倍數（雙倍）餘額遞減法$2,880"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00025', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年底編製財務報表時，經帳齡分析後估計應收帳款中有$5,000將無法收回，因而報 導「備抵壞帳」為$5,000。到了X2年，該公司實際沖銷了$8,000的應收帳款，並於X2年底再次 根據帳齡分析，估計應收帳款中仍有$22,000將無法收回。請問：X2年應認列「壞帳費用」為何？ X2年底「備抵壞帳」餘額應為多少？', '["壞帳費用$22,000，備抵壞帳$14,000", "壞帳費用$25,000，備抵壞帳$22,000", "壞帳費用$19,000，備抵壞帳$22,000", "壞帳費用$17,000，備抵壞帳$22,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00026', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年發生以下商品交易（單位：件）： 1月1日：期初存貨100件，單位成本$10 3月1日：進貨200件，單位成本$12 7月1日：銷貨250件 11月1日：進貨100件，單位成本$13 已知該公司採用先進先出法計算存貨成本。請問：截至X1年12月31日，銷貨成本與期末存貨 金額為何？', '["銷貨成本$2,800，期末存貨$1,900", "銷貨成本$2,600，期末存貨$2,100", "銷貨成本$2,900，期末存貨$1,800", "銷貨成本$2,700，期末存貨$2,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "27bafe9f77b8", "answer_pdf_sha1": "05188d53fc6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
